import os
import json
import logging
import azure.functions as func
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient
from azure.eventgrid import EventGridPublisherClient
from azure.identity import ManagedIdentityCredential

# Function to process the incoming blob
def main(blob: func.InputStream):
    logging.info(f"Processing blob: {blob.name}, Size: {blob.length} bytes")

    # Get environment variables
    cosmos_uri = os.getenv("COSMOS_DB_URI")
    cosmos_key = os.getenv("COSMOS_DB_KEY")
    event_grid_topic_endpoint = os.getenv("EVENT_GRID_TOPIC_ENDPOINT")

    # Initialize Managed Identity Credential
    credential = ManagedIdentityCredential()

    # Connect to Blob Storage
    blob_service_client = BlobServiceClient(account_url=os.getenv("AZURE_STORAGE_ACCOUNT_URL"), credential=credential)

    # Connect to Cosmos DB
    cosmos_client = CosmosClient(cosmos_uri, credential=credential)

    # Prepare to write to Cosmos DB
    database_name = os.getenv("COSMOS_DB_DATABASE")
    container_name = os.getenv("COSMOS_DB_CONTAINER")
    container = cosmos_client.get_database_client(database_name).get_container_client(container_name)

    # Process the file (example: count words)
    content = blob.read().decode('utf-8')
    word_count = len(content.split())

    # Write to Cosmos DB
    item = {
        "id": blob.name,
        "word_count": word_count,
        "processed_time": blob.last_modified.isoformat()
    }
    container.upsert_item(item)

    # Initialize Event Grid client
    event_grid_client = EventGridPublisherClient(event_grid_topic_endpoint, credential=credential)

    # Send notification to Event Grid
    event_data = {
        "id": blob.name,
        "event_type": "BlobProcessed",
        "subject": f"Blob/{blob.name}",
        "data": item,
        "event_time": blob.last_modified.isoformat(),
        "data_version": "1.0"
    }
    event_grid_client.send(event_data)

    logging.info(f"Blob processed and results written to Cosmos DB and notification sent to Event Grid.")